3. Define the Model

class LinearModel(nn.Module):
    def __init__(self):
        super().__init__()
        self.linear = nn.Linear(1, 1)

    def forward(self, x):
        return self.linear(x).squeeze(-1)

model = LinearModel()
print(model)
print(f"Parameters: {sum(p.numel() for p in model.parameters())}")

